<?php$case_slider_h2 = get_field('case_slider_h2'); //text$case_slider_btn = get_field('case_slider_btn'); //link$case_sliders = get_field('case_sliders'); //repeater?><?php if ($case_studies): ?> <section class="cases">  <div class="cases__container container">    <div class="cases__header">      <h2 class="cases__title gradient-text title-xs"><?php echo $case_slider_h2; ?></h2>	  <?php if ($case_slider_btn) {		  $link_url = $case_slider_btn['url'];		  $link_title = $case_slider_btn['title'];		  $link_target = $case_slider_btn['target'] ? $case_slider_btn['target'] : '_self';		  	  ?>	  <a class="cases__more btn btn-grey btn-md" href="<?php echo esc_url( $link_url ); ?>" target="<?php echo esc_attr( $link_target ); ?>"><?php echo esc_html( $link_title ); ?></a>	  <?php } ?>    </div>    <div class="cases__slider swiper">      <ul class="swiper-wrapper"> 	  <?php foreach ($case_sliders as $case): ?> <li class="case-card swiper-slide">          <a href="<?php echo esc_url($case['link']); ?>" class="case-card__link-wrapper">            <picture class="case-card__image">              <source srcset="<?php echo IMG_PATH . '/cases/' . $case['img_webp']; ?>" type="image/webp">              <img src="<?php echo IMG_PATH . '/cases/' . $case['img_jpg']; ?>" 			  alt="<?php echo esc_attr($case['name']); ?>" class="cover-image" loading="lazy">            </picture>            <div class="case-card__details">              <div class="case-card__details-main">                <div class="case-card__name"> <?php echo esc_html($case['name']); ?> </div>                <p class="case-card__desc"> <?php echo esc_html($case['desc']); ?> </p>              </div>              <div class="case-card__arrow icon-long-arrow"></div>            </div>          </a>        </li> <?php endforeach; ?> </ul>    </div>  </div></section> <?php endif; ?>